mapper.select:
SELECT
FROM customer_service_ticket t LEFT JOIN sys_user u ON u.user_id = t.user_id LEFT JOIN sys_user a ON a.user_id = t.admin_id LEFT JOIN delivery_order o ON o.order_id = t.order_id LEFT JOIN merchant_info mi ON mi.merchant_id = o.merchant_id LEFT JOIN sys_user mu ON mu.user_id = o.merchant_id WHERE t.user_id = #{userId}
AND t.status = #{status}
ORDER BY t.update_time DESC, t.ticket_id DESC

SELECT COUNT(1)
FROM delivery_order
WHERE order_id = #{orderId}
  AND user_id = #{userId}

mapper.update:
UPDATE customer_service_ticket
SET update_time = NOW()
WHERE ticket_id = #{ticketId}

UPDATE customer_service_message
SET is_read = 1
WHERE ticket_id = #{ticketId}
  AND sender_role != #{readerRole}
